# ROBUSTNESS PHASE D — Customer journey and multi-ECU regression
# Manually written, not generated by testgen.py. Do not delete.
#
# Simulates real customer workflows: install from scratch, generate a new ECU
# config, add a DID and regenerate. Also validates all 11 ECU example configs
# produce passing pytest suites in simulator mode — end-to-end product integrity.
#
# Run: pytest test_robustness_D_customer_journey.py -v
from __future__ import annotations

import os
import subprocess
import sys
import tempfile
import textwrap

import pytest

EDS_ROOT  = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", "..", ".."))
CODEGEN   = os.path.join(EDS_ROOT, "tools", "codegen.py")
