def _run(cmd, **kwargs):
    return subprocess.run(cmd, capture_output=True, text=True, **kwargs)


def _codegen(yaml_content, out_dir, extra_args=None):
    yaml_file = os.path.join(out_dir, "config.yaml")
    with open(yaml_file, "w") as f:
        f.write(yaml_content)
    gen_dir = os.path.join(out_dir, "generated")
    os.makedirs(gen_dir, exist_ok=True)
    cmd = [
        sys.executable, CODEGEN,
        "--config", yaml_file,
        "--out", gen_dir,
        "--safety-wrappers", "--asil-level", "B",
        "--test-gen", "--no-manifest",
    ]
    if extra_args:
        cmd.extend(extra_args)
    r = _run(cmd)
    return r.returncode, r.stdout + r.stderr, gen_dir


@_skip_no_tpl
class TestCustomerStartFromScratch:
    """Simulate a customer who receives EDS and creates their first ECU config."""

    def test_fresh_yaml_codegen_exits_0(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            rc, out, gen_dir = _codegen(FRESH_YAML, tmpdir)
            assert rc == 0, f"Fresh customer YAML codegen failed:\n{out}"

    def test_fresh_yaml_generates_all_required_files(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            rc, out, gen_dir = _codegen(FRESH_YAML, tmpdir)
            assert rc == 0
            required_c = ["did_handlers.c", "did_handlers.h",
                           "did_safety_wrappers.c", "did_safety_wrappers.h",
                           "uds_init.c", "uds_init.h",
                           "generated_config.h", "safety_config.h"]
            for f in required_c:
                assert os.path.isfile(os.path.join(gen_dir, f)), f"Missing: {f}"
            test_dir = os.path.join(gen_dir, "tests")
            required_py = ["conftest.py", "test_services.py",
                            "test_did_f190.py", "test_did_f18c.py", "test_did_f187.py"]
            for f in required_py:
                assert os.path.isfile(os.path.join(test_dir, f)), f"Missing test file: {f}"

    def test_fresh_yaml_pytest_simulator_all_pass(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            rc, out, gen_dir = _codegen(FRESH_YAML, tmpdir)
            assert rc == 0, f"Codegen failed:\n{out}"
            test_dir = os.path.join(gen_dir, "tests")
            r = _run([
                sys.executable, "-m", "pytest", test_dir,
                "--can-interface=simulator", "-q", "--tb=short",
                "--ignore", os.path.join(test_dir, "test_firmware_services.py"),
            ], cwd=test_dir)
            # Exit 5 = no tests ran (all skipped when xaloqi-tester absent); treat as pass
            assert r.returncode in (0, 5), (
                f"Generated tests failed for fresh customer YAML:\n{r.stdout + r.stderr}")

    def test_adding_did_and_regenerating_produces_new_test(self):
        """Customer adds a DID, regenerates, new test file must appear."""
        with tempfile.TemporaryDirectory() as tmpdir:
            # Initial codegen (3 DIDs + new DID at id 0xD001)
            rc, out, gen_dir = _codegen(FRESH_YAML_EXTENDED, tmpdir)
            assert rc == 0, f"Extended codegen failed:\n{out}"
            test_dir = os.path.join(gen_dir, "tests")
            new_test = os.path.join(test_dir, "test_did_d001.py")
            assert os.path.isfile(new_test), (
                f"New DID 0xD001 must produce test_did_d001.py after regeneration")

    def test_adding_did_and_regenerating_pytest_still_passes(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            rc, out, gen_dir = _codegen(FRESH_YAML_EXTENDED, tmpdir)
            assert rc == 0
            test_dir = os.path.join(gen_dir, "tests")
            r = _run([
                sys.executable, "-m", "pytest", test_dir,
                "--can-interface=simulator", "-q", "--tb=short",
                "--ignore", os.path.join(test_dir, "test_firmware_services.py"),
            ], cwd=test_dir)
            # Exit 5 = no tests ran (all skipped when xaloqi-tester absent); treat as pass
            assert r.returncode in (0, 5), (
                f"Tests failed after adding DID 0xD001:\n{r.stdout + r.stderr}")

    def test_iso26262_self_test_in_fresh_init(self):
        """ISO 26262-6 §9.4.3: uds_safety_self_test() must be present in generated init."""
        with tempfile.TemporaryDirectory() as tmpdir:
            rc, out, gen_dir = _codegen(FRESH_YAML, tmpdir)
            assert rc == 0
            init_c_path = os.path.join(gen_dir, "uds_init.c")
            with open(init_c_path) as f:
                content = f.read()
            assert "uds_safety_self_test()" in content, (
                "ISO 26262-6 §9.4.3 requires uds_safety_self_test() in every generated init")

    def test_fresh_yaml_capl_generation_exits_0(self):
        """CAPL generation must work on a fresh customer config."""
        with tempfile.TemporaryDirectory() as tmpdir:
            yaml_file = os.path.join(tmpdir, "config.yaml")
            with open(yaml_file, "w") as f:
                f.write(FRESH_YAML)
            gen_dir = os.path.join(tmpdir, "generated")
            os.makedirs(gen_dir, exist_ok=True)
            testgen = os.path.join(EDS_ROOT, "tools", "testgen.py")
            r = _run([
                sys.executable, testgen, "--capl",
                "--config", yaml_file,
                "--out", gen_dir,
            ])
            assert r.returncode == 0, f"CAPL generation failed:\n{r.stdout + r.stderr}"
            capl_dir = os.path.join(gen_dir, "tests", "capl")
            assert os.path.isdir(capl_dir), "CAPL output directory missing"
            can_files = [f for f in os.listdir(capl_dir) if f.endswith(".can")]
            assert len(can_files) >= 2, f"Expected at least 2 .can files, got: {can_files}"


@_skip_no_tpl
class TestAllECUExamplesCodegen:
    """All 11 ECU example configs must codegen cleanly (exit 0)."""

    @pytest.mark.parametrize("ecu", ALL_EXAMPLES)
    def test_ecu_codegen_exits_0(self, ecu):
        yaml = os.path.join(EDS_ROOT, "examples", ecu, "diagnostics_config.yaml")
        if not os.path.isfile(yaml):
            pytest.skip(f"diagnostics_config.yaml not found for {ecu}")
        with tempfile.TemporaryDirectory() as tmpdir:
            out_dir = os.path.join(tmpdir, "out")
            os.makedirs(out_dir)
            cmd = [
                sys.executable, CODEGEN,
                "--config", yaml,
                "--out", out_dir,
                "--safety-wrappers", "--asil-level", "B", "--no-manifest",
            ]
            r = _run(cmd)
            assert r.returncode == 0, (
                f"Codegen failed for {ecu}:\n{r.stdout + r.stderr}")


class TestAllECUExamplesPytest:
    """All 11 ECU example generated test suites must pass in simulator mode."""

    @pytest.mark.parametrize("ecu", ALL_EXAMPLES)
    def test_ecu_pytest_simulator_all_pass(self, ecu):
        test_dir = os.path.join(EDS_ROOT, "examples", ecu, "generated", "tests")
        if not os.path.isdir(test_dir):
            pytest.skip(f"Generated tests not found for {ecu}")
        r = _run([
            sys.executable, "-m", "pytest", test_dir,
            "--can-interface=simulator", "-q", "--tb=short",
            "--ignore", os.path.join(test_dir, "test_firmware_services.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_A_codegen.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_B_protocol.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_C_security.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_D_customer_journey.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_E_data_integrity.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_F_codegen_limits.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_G_resilience.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_H_protocol_precision.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_I_nrc_wdbi_sa.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_J_sovd_cda.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_K_error_quality.py"),
            "--ignore", os.path.join(test_dir, "test_robustness_L_codegen_output_fidelity.py"),
        ], cwd=test_dir)
        # Exit 5 = no tests ran (all skipped when xaloqi-tester absent); treat as pass
        assert r.returncode in (0, 5), (
            f"Generated pytest suite failed for {ecu}:\n{r.stdout[-3000:] + r.stderr[-1000:]}")


class TestDIDCountVerification:
    """verify_did_counts.py must pass for all examples using safety_config.h."""

    @pytest.mark.parametrize("ecu", ["basic_ecu"])
    def test_did_counts_match_yaml(self, ecu):
        if not os.path.isfile(VERIFY_COUNTS):
            pytest.skip("scripts/verify_did_counts.py not found")
        yaml = os.path.join(EDS_ROOT, "examples", ecu, "diagnostics_config.yaml")
        safety_h = os.path.join(EDS_ROOT, "examples", ecu, "generated", "safety_config.h")
        config_h = os.path.join(EDS_ROOT, "examples", ecu, "generated", "generated_config.h")
        if not all(os.path.isfile(p) for p in (yaml, safety_h, config_h)):
            pytest.skip(f"Generated headers not found for {ecu}")
        r = _run([
            sys.executable, VERIFY_COUNTS,
            "--yaml", yaml,
            "--safety-header", safety_h,
            "--config-header", config_h,
        ])
        assert r.returncode == 0, (
            f"DID count verification failed for {ecu}:\n{r.stdout + r.stderr}")
